const h3 = require('h3-js');

// Get H3 cell for a lat/lon and its ring of neighbors (radius 1)
const lat = 37.775938728915946;
const lon = -122.41795063018799;
const resolution = 9; // tune by density
const cell = h3.geoToH3(lat, lon, resolution);
const neighbors = h3.kRing(cell, 1); // includes origin

console.log('cell', cell);
console.log('neighbors', neighbors.length, neighbors.slice(0,10));
